import{_ as a,o as i,c as s,ag as c}from"./chunks/framework.CAXxHpAX.js";const y=JSON.parse('{"title":"辛亥革命的历史意义：推翻了清朝的统治，宣","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-22.md","filePath":"notes/note-22.md"}'),l={name:"notes/note-22.md"};function v(r,d,e,o,t,n){return i(),s("div",null,[...d[0]||(d[0]=[c('<h1 id="辛亥革命的历史意义-推翻了清朝的统治-宣" tabindex="-1">辛亥革命的历史意义：推翻了清朝的统治，宣 <a class="header-anchor" href="#辛亥革命的历史意义-推翻了清朝的统治-宣" aria-label="Permalink to &quot;辛亥革命的历史意义：推翻了清朝的统治，宣&quot;">​</a></h1><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">辛亥革命的历史意义：</span>推翻了清朝的统治，宣告两千多年的封建君主专制终结；开创了近代民族民主革命；建立了第一个资产阶级共和国——中华民国；推动近代民族工业的发展；极大推动中华民族思想解放，打开了中国进步潮流的闸门；推动了社会观念的转变和平等自由思想的普及，促使社会移风易俗。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">局限性：</span>没有改变中国半殖民地半封建社会的性质，没有完成反帝反封建的革命任务。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">长征胜利的意义：</span>粉碎了国民党反动派消灭红军的企图，保存了党和红军的基干力量，使中国革命转危为安，红军长征播下革命种子，铸就长征精神（独立自主、实事求是），打开了中国革命的新局面。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">遵义会议：</span>1935年1月，开始确立以毛泽东为主要代表的马克思主义正确路线在中共中央的领导地位；在极其危急的情况下，挽救了党，挽救了红军，挽救了中国革命，是中共历史上一个生死攸关得转折点，是中共从幼年走向成熟的标志。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">中共十一届三中全会：</span></p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>①是新中国成立以来党和国家历史上具有深远意义的伟大转折，开启了改革开放和社会主义现代化建设的新时期。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>②形成以邓小平为核心的第二代中央领导集体。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">农村经济体制改革内容：</span>1978年，家庭联产承包责任制、分田包干到户、自负盈亏</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">作用：</span></p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>①农民有了生产自主权，激发农民的劳动热情，生产积极性提高，带来了农村生产力解放，农业生产和农民收入均有很大提高；</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>②农业生产向专业化、商品化、社会化发展，推动农村乡镇企业发展，为农民致富和实现现代化开辟了一条新路。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">城市经济体制改革：</span>1984年，中心环节：增强企业活力。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">城市经济体制改革的意义：</span>企业有了经营自主权；大大调动了企业、职工的积极性，增强了企业的活力。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">经济特区：</span>1980年，深圳（窗口）、珠海、汕头、厦门。1984年，广州沿海开放城市。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">经济特区的作用：</span>引进外资、先进技术和管理经验，推动国内的进一步改革，扩大对外经济交流，发展社会主义现代化事业起到重要作用。</p></div><div class="circle-overlay"></div></div></div>',16)])])}const b=a(l,[["render",v]]);export{y as __pageData,b as default};
